// MARK: - BiometricAuthManager

class BiometricAuthManager {
    
    static let shared = BiometricAuthManager()
    
    private let keychainService = "com.myapp.authentication"
    private let keychainAccount = "biometricAuthEnabled"
    private let authenticatedKey = "isUserAuthenticated"
    private let biometricEnabledKey = "isBiometricEnabled"
    
    enum BiometricType {
        case none
        case touchID
        case faceID
    }
    
    enum AuthenticationError: Error, LocalizedError {
        case biometryNotAvailable
        case biometryNotEnrolled
        case biometryLockout
        case userCancel
        case userFallback
        case authenticationFailed
        case unknown(Error)
        
        var errorDescription: String? {
            switch self {
            case .biometryNotAvailable:
                return "Biometric authentication is not available on this device."
            case .biometryNotEnrolled:
                return "No biometric data is enrolled. Please set up Face ID or Touch ID in Settings."
            case .biometryLockout:
                return "Biometric authentication is locked due to too many failed attempts. Please use your password."
            case .userCancel:
                return "Authentication was cancelled."
            case .userFallback:
                return "User chose to use password."
            case .authenticationFailed:
                return "Authentication failed. Please try again."
            case .unknown(let error):
                return error.localizedDescription
            }
        }
    }
    
    private init() {}
    
    // MARK: - Biometric Type Detection
    
    var biometricType: BiometricType {
        let context = LAContext()
        var error: NSError?
        guard context.canEvaluatePolicy(.deviceOwnerAuthenticationWithBiometrics, error: &error) else {
            return .none
        }
        switch context.biometryType {
        case .touchID:
            return .touchID
        case .faceID:
            return .faceID
        case .opticID:
            return .none
        @unknown default:
            return .none
        }
    }
    
    var biometricTypeString: String {
        switch biometricType {
        case .faceID:
            return "Face ID"
        case .touchID:
            return "Touch ID"
        case .none:
            return "None"
        }
    }
    
    var isBiometricAvailable: Bool {
        let context = LAContext()
        var error: NSError?
        return context.canEvaluatePolicy(.deviceOwnerAuthenticationWithBiometrics, error: &error)
    }
    
    // MARK: - Authentication State
    
    var isBiometricEnabled: Bool {
        get { UserDefaults.standard.bool(forKey: biometricEnabledKey) }
        set { UserDefaults.standard.set(newValue, forKey: biometricEnabledKey) }
    }
    
    var isUserAuthenticated: Bool {
        get { UserDefaults.standard.bool(forKey: authenticatedKey) }
        set { UserDefaults.standard.set(newValue, forKey: authenticatedKey) }
    }
    
    // MARK: - Keychain Storage
    
    func storeAuthToken(_ token: String) -> Bool {
        let data = Data(token.utf8)
        
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: keychainService,
            kSecAttrAccount as String: keychainAccount,
            kSecValueData as String: data,
            kSecAttrAccessible as String: kSecAttrAccessibleWhenUnlockedThisDeviceOnly
        ]
        
        SecItemDelete(query as CFDictionary)
        
        let status = SecItemAdd(query as CFDictionary, nil)
        return status == errSecSuccess
    }
    
    func retrieveAuthToken() -> String? {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: keychainService,
            kSecAttrAccount as String: keychainAccount,
            kSecReturnData as String: true,
            kSecMatchLimit as String: kSecMatchLimitOne
        ]
        
        var result: AnyObject?
        let status = SecItemCopyMatching(query as CFDictionary, &result)
        
        guard status == errSecSuccess, let data = result as? Data else {
            return nil
        }
        
        return String(data: data, encoding: .utf8)
    }
    
    func deleteAuthToken() {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: keychainService,
            kSecAttrAccount as String: keychainAccount
        ]
        SecItemDelete(query as CFDictionary)
    }
    
    // MARK: - Biometric Authentication
    
    func authenticateWithBiometrics(reason: String? = nil, completion: @escaping (Result<Bool, AuthenticationError>) -> Void) {
        let context = LAContext()
        context.localizedCancelTitle = "Use Password"
        context.localizedFallbackTitle = "Enter Password"
        
        var error: NSError?
        
        guard context.canEvaluatePolicy(.deviceOwnerAuthenticationWithBiometrics, error: &error) else {
            if let laError = error as? LAError {
                completion(.failure(mapLAError(laError)))
            } else {
                completion(.failure(.biometryNotAvailable))
            }
            return
        }
        
        let authReason = reason ?? "Authenticate to access your account"
        
        context.evaluatePolicy(.deviceOwnerAuthenticationWithBiometrics, localizedReason: authReason) { success, error in
            DispatchQueue.main.async {
                if success {
                    self.isUserAuthenticated = true
                    completion(.success(true))
                } else if let laError = error as? LAError {
                    completion(.failure(self.mapLAError(laError)))
                } else {
                    completion(.failure(.authenticationFailed))
                }
            }
        }
    }
    
    func enableBiometricLogin(forUsername username: String, password: String, completion: @escaping (Result<Bool, AuthenticationError>) -> Void) {
        authenticateWithBiometrics(reason: "Enable \(biometricTypeString) for quick login") { result in
            switch result {
            case .success:
                let credentials = "\(username):\(password)"
                if self.storeAuthToken(credentials) {
                    self.isBiometricEnabled = true
                    completion(.success(true))
                } else {
                    completion(.failure(.authenticationFailed))
                }
            case .failure(let error):
                completion(.failure(error))
            }
        }
    }
    
    func disableBiometricLogin() {
        isBiometricEnabled = false
        isUserAuthenticated = false
        deleteAuthToken()
    }
    
    func logout() {
        isUserAuthenticated = false
    }
    
    // MARK: - Private Helpers
    
    private func mapLAError(_ error: LAError) -> AuthenticationError {
        switch error.code {
        case .biometryNotAvailable:
            return .biometryNotAvailable
        case .biometryNotEnrolled:
            return .biometryNotEnrolled
        case .biometryLockout:
            return .biometryLockout
        case .userCancel:
            return .userCancel
        case .userFallback:
            return .userFallback
        case .authenticationFailed:
            return .authenticationFailed
        default:
            return .unknown(error)
        }
    }
}

