            self?.navigateToLogin()
        })
        
        alert.addAction(UIAlertAction(title: "Cancel", style: .cancel))
        
        present(alert, animated: true)
    }
    
    private func navigateToLogin() {
        let loginVC = LoginViewController()
        
        if let windowScene = UIApplication.shared.connectedScenes.first as? UIWindowScene,
           let window = windowScene.windows.first {
            UIView.transition(with: window, duration: 0.3, options: .transitionCrossDissolve) {
                window.rootViewController = loginVC
            }
        }
    }
}

// MARK: - AppFlowController

class AppFlowController {
    
    static let shared = AppFlowController()
    
    private let authManager = BiometricAuthManager.shared
    
    private init() {}
    
    func determineInitialViewController() -> UIViewController {
        if authManager.isUserAuthenticated && authManager.isBiometricEnabled {
            // User was previously authenticated and has biometrics enabled
            // Show a biometric challenge before granting access
            let launchVC = BiometricLaunchViewController()
            return launchVC
        } else if authManager.isUserAuthenticated {
            // User is authenticated but no biometrics
            let mainVC = MainAppViewController()
            return UINavigationController(rootViewController: mainVC)
        } else {
            // Not authenticated - show login
            return LoginViewController()
        }
    }
}

// MARK: - BiometricLaunchViewController

class BiometricLaunchViewController: UIViewController {
    
    private let authManager = BiometricAuthManager.shared
    
    private let logoImageView: UIImageView = {
        let iv = UIImageView()
        iv.image = UIImage(systemName: "lock.shield.fill")
        iv.tintColor = .systemBlue
        iv.contentMode = .scaleAspectFit
        iv.translatesAutoresizingMaskIntoConstraints = false
        return iv
    }()
    
    private let messageLabel: UILabel = {
        let label = UILabel()
        label.text = "Authenticate to continue"
        label.font = .systemFont(ofSize: 18, weight: .medium)
        label.textColor = .secondaryLabel
        label.textAlignment = .center
        label.translatesAutoresizingMaskIntoConstraints = false
        return label
    }()
    
    private let retryButton: UIButton = {
        let button = UIButton(type: .system)
        button.setTitle("Try Again", for: .normal)
        button.titleLabel?.font = .systemFont(ofSize: 16, weight: .semibold)
        button.isHidden = true
        button.translatesAutoresizingMaskIntoConstraints = false
        return button
    }()
    
    private let usePasswordButton: UIButton = {
        let button = UIButton(type: .system)
        button.setTitle("Use Password Instead", for: .normal)
        button.titleLabel?.font = .systemFont(ofSize: 16, weight: .medium)
        button.isHidden = true
        button.translatesAutoresizingMaskIntoConstraints = false
        return button
    }()
    
    override func viewDidLoad() {
        super.viewDidLoad()
        setupUI()
        retryButton.addTarget(self, action: #selector(retryTapped), for: .touchUpInside)
        usePasswordButton.addTarget(self, action: #selector(usePasswordTapped), for: .touchUpInside)
    }
    
    override func viewDidAppear(_ animated: Bool) {
        super.viewDidAppear(animated)
        performBiometricAuth()
    }
    
    private func setupUI() {
        view.backgroundColor = .systemBackground
        
        view.addSubview(logoImageView)
        view.addSubview(messageLabel)
        view.addSubview(retryButton)
        view.addSubview(usePasswordButton)
        
        NSLayoutConstraint.activate([
            logoImageView.centerXAnchor.constraint(equalTo: view.centerXAnchor),
            logoImageView.centerYAnchor.constraint(equalTo: view.centerYAnchor, constant: -60),
            logoImageView.widthAnchor.constraint(equalToConstant: 80),
            logoImageView.heightAnchor.constraint(equalToConstant: 80),
            
            messageLabel.topAnchor.constraint(equalTo: logoImageView.bottomAnchor, constant: 24),
            messageLabel.leadingAnchor.constraint(equalTo: view.leadingAnchor, constant: 32),
            messageLabel.trailingAnchor.constraint(equalTo: view.trailingAnchor, constant: -32),
            
            retryButton.topAnchor.constraint(equalTo: messageLabel.bottomAnchor, constant: 24),
            retryButton.centerXAnchor.constraint(equalTo: view.centerXAnchor),
            
            usePasswordButton.topAnchor.constraint(equalTo: retryButton.bottomAnchor, constant: 16),
            usePasswordButton.centerXAnchor.constraint(equalTo: view.centerXAnchor)
        ])
    }
    
    private func performBiometricAuth() {
        authManager.authenticateWithBiometrics { [weak self] result in
            guard let self = self else { return }
            
            switch result {
            case .success:
                self.navigateToMainApp()
                
            case .failure(let error):
                switch error {
                case .userCancel, .userFallback:
                    self.showFallbackOptions()
                case .biometryLockout:
                    self.messageLabel.text = "Biometric locked. Please use your password."
                    self.showFallbackOptions()
                default:
                    self.messageLabel.text = error.localizedDescription
                    self.showFallbackOptions()
                }
            }
        }
    }
    
    private func showFallbackOptions() {
        retryButton.isHidden = false
        usePasswordButton.isHidden = false
    }
    
    @objc private func retryTapped() {
        retryButton.isHidden = true
        usePasswordButton.isHidden = true
        messageLabel.text = "Authenticate to continue"
        performBiometricAuth()
    }
    
    @objc private func usePasswordTapped() {
        authManager.logout()
        navigateToLogin()
    }
    
    private func navigateToMainApp() {
        let mainVC = MainAppViewController()
        if let windowScene = UIApplication.shared.connectedScenes.first as? UIWindowScene,
           let window = windowScene.windows.first {
            UIView.transition(with: window, duration: 0.3, options: .transitionCrossDissolve) {
                window.rootViewController = UINavigationController(rootViewController: mainVC)
            }
        }
    }
    
    private func navigateToLogin() {
        let loginVC = LoginViewController()
        if let windowScene = UIApplication.shared.connectedScenes.first as? UIWindowScene,
           let window = windowScene.windows.first {
            UIView.transition(with: window, duration: 0.3, options: .transitionCrossDissolve) {
                window.rootViewController = loginVC
            }
        }
    }
}

// MARK: - SceneDelegate Integration

class SceneDelegate: UIResponder, UIWindowSceneDelegate {
    
    var window: UIWindow?
    
    func scene(_ scene: UIScene, willConnectTo session: UISceneSession, options connectionOptions: UIScene.ConnectionOptions) {
        guard let windowScene = (scene as? UIWindowScene) else { return }
        
        window = UIWindow(windowScene: windowScene)
        window?.rootViewController = AppFlowController.shared.determineInitialViewController()
        window?.makeKeyAndVisible()
    }
    
    func sceneDidBecomeActive(_ scene: UIScene) {
        // Optional: Re-authenticate when app becomes active after being in background
    }
    
    func sceneWillResignActive(_ scene: UIScene) {
        // Optional: Add privacy screen overlay
    }
}